<script>
const mygoContainer = document.querySelector('.mygo-container');
const choiceGrid = document.getElementById('choiceGrid');
const settingsPanel = document.getElementById('settingsPanel');
const settingsBtn = document.querySelector('.settings-btn');
const fontSizeSlider = document.querySelector('.range-input');
const fontColorPicker = document.querySelector('.color-input');
const themeDefaultColors = {'cyber':'#e8f4f8','mystic':'#e8f4f8','forest':'#e8f4f8','royal':'#e8f4f8','mono':'#dddddd','sakura':'#8b4563','sunset':'#fff5ee','crimson':'#ffe6e6'};

function toggleSettings(){settingsPanel.classList.toggle('active')}
function setLayout(type){const btns=document.querySelectorAll('.layout-options .option-btn');btns.forEach(b=>b.classList.remove('active'));if(type==='vertical'){choiceGrid.classList.add('vertical');btns[1].classList.add('active')}else{choiceGrid.classList.remove('vertical');btns[0].classList.add('active')}localStorage.setItem('layout',type)}
function setMode(mode){const btns=document.querySelectorAll('.mode-options .option-btn');btns.forEach(b=>b.classList.remove('active'));if(mode==='send'){btns[1].classList.add('active')}else{btns[0].classList.add('active')}localStorage.setItem('sendMode',mode)}
function setTheme(theme){mygoContainer.className='mygo-container theme-'+theme;document.querySelectorAll('.theme-btn').forEach(b=>b.classList.remove('active'));document.querySelector('.theme-btn.'+theme).classList.add('active');localStorage.setItem('theme',theme);if(localStorage.getItem('fontColor')===null){resetFontColor()}}
function setFontSize(val){document.documentElement.style.setProperty('--c-size',val+'px');localStorage.setItem('fontSize',val)}
function setFontColor(val){mygoContainer.style.setProperty('--c-color',val);localStorage.setItem('fontColor',val)}
function resetFontColor(){mygoContainer.style.removeProperty('--c-color');localStorage.removeItem('fontColor');const currentTheme=mygoContainer.classList[1].replace('theme-','');fontColorPicker.value=themeDefaultColors[currentTheme]||'#e8f4f8'}
function resetAllSettings(){if(confirm('Bạn có chắc chắn muốn khôi phục tất cả cài đặt gốc không?')){['layout','sendMode','theme','fontSize','fontColor'].forEach(k=>localStorage.removeItem(k));window.location.reload()}}
function handleStoryClick(btnElement) {
    // 1. Lấy nội dung text từ div con .choice-text
    const textDiv = btnElement.querySelector('.choice-text');
    if (!textDiv) return;

    // Lấy text thuần túy, loại bỏ khoảng trắng thừa đầu đuôi
    const text = textDiv.innerText.trim();

    // 2. Tìm khung chat trong parent (Silly Tavern)
    const textarea = parent.document.querySelector('#send_textarea');

    if (textarea) {
        // Set giá trị
        textarea.value = text;

        // Dispatch event input để Vue/React của Silly Tavern cập nhật state
        textarea.dispatchEvent(new Event('input', { bubbles: true }));
        textarea.focus();

        // 3. Kiểm tra chế độ gửi
        if (localStorage.getItem('sendMode') === 'send') {
            const sendBtn = parent.document.querySelector('#send_but');
            if (sendBtn) {
                // Delay cực ngắn để đảm bảo biến textarea đã update
                setTimeout(() => sendBtn.click(), 50); 
            }
        }
    } else {
        console.error("MyGO Error: Không tìm thấy #send_textarea. Hãy kiểm tra lại ID của Silly Tavern.");
        alert("Lỗi: Không tìm thấy khung chat của Silly Tavern!");
    }
}

window.addEventListener('load',()=>{
    const savedTheme = localStorage.getItem('theme') || 'cyber';
    setTheme(savedTheme);
    setLayout(localStorage.getItem('layout')||'grid');
    setMode(localStorage.getItem('sendMode')||'fill');
    const savedFontSize = localStorage.getItem('fontSize');
    if(savedFontSize){setFontSize(savedFontSize);fontSizeSlider.value=savedFontSize}
    const savedFontColor = localStorage.getItem('fontColor');
    if(savedFontColor){setFontColor(savedFontColor);fontColorPicker.value=savedFontColor}
    else{resetFontColor()}
});

document.addEventListener('click',e=>{if(!settingsPanel.contains(e.target)&&!settingsBtn.contains(e.target))settingsPanel.classList.remove('active')});
</script>
</body>
