.settings-section{margin-bottom:14px}
.settings-section:last-child{margin-bottom:0}
.settings-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:8px}
.settings-label{font-size:13px;font-weight:700;display:block;transition:color 0.4s}
.reset-text{font-size:11px;cursor:pointer;opacity:0.7;text-decoration:underline;border:none;background:none;color:inherit;padding:0}
.reset-text:hover{opacity:1}
.layout-options,.mode-options{display:flex;gap:8px}
.theme-options{display:flex;gap:8px;flex-wrap:wrap;justify-content:center}
.option-btn{flex:1;padding:8px 6px;background:rgba(255,255,255,0.1);border:2px solid rgba(255,255,255,0.2);border-radius:8px;color:#e8f4f8;font-size:12px;cursor:pointer;transition:all 0.25s;text-align:center}
.option-btn:hover{background:rgba(255,255,255,0.2)}
.option-btn.active{background:rgba(255,255,255,0.25);border-color:rgba(255,215,0,0.6);box-shadow:0 0 12px rgba(255,215,0,0.3)}
.theme-btn{width:36px;height:36px;border-radius:50%;cursor:pointer;transition:all 0.25s;position:relative;border:3px solid rgba(255,255,255,0.4)}
.theme-btn:hover{transform:scale(1.2)}
.theme-btn.active{border-width:4px;border-color:#fff;box-shadow:0 0 20px currentColor,inset 0 0 10px rgba(255,255,255,0.3)}
.theme-btn.cyber{background:linear-gradient(135deg,#00f5ff,#0077b6,#00d4ff)}
.theme-btn.mystic{background:linear-gradient(135deg,#ff6fd8,#9d4edd,#3c096c)}
.theme-btn.forest{background:linear-gradient(135deg,#95d5b2,#2d6a4f,#1b4332)}
.theme-btn.royal{background:linear-gradient(135deg,#ffd700,#b8860b,#8b4513)}
.theme-btn.mono{background:linear-gradient(135deg,#ffffff,#888888,#000000)}
.theme-btn.sakura{background:linear-gradient(135deg,#ffc0cb,#ffb7b2,#ff9a9e)}
.theme-btn.sunset{background:linear-gradient(135deg,#ff9966,#ff5e62,#ff0000)}
.theme-btn.crimson{background:linear-gradient(135deg,#800000,#4a0000,#000000)}
.range-input{width:100%;height:6px;background:rgba(255,255,255,0.2);border-radius:4px;outline:none;-webkit-appearance:none;cursor:pointer}
.range-input::-webkit-slider-thumb{-webkit-appearance:none;width:16px;height:16px;background:#fff;border-radius:50%;cursor:pointer;transition:all 0.2s}
.range-input::-webkit-slider-thumb:hover{transform:scale(1.2)}
.color-input{width:100%;height:30px;border:none;background:transparent;cursor:pointer;padding:0}
.choice-grid{display:grid;grid-template-columns:1fr 1fr;gap:14px;position:relative;z-index:1;transition:all 0.3s ease}
.choice-grid.vertical{grid-template-columns:1fr;gap:12px}
.choice-btn{width:100%;border-radius:14px;padding:16px 14px;cursor:pointer;transition:all 0.35s cubic-bezier(0.4,0,0.2,1);text-align:left;position:relative;overflow:hidden;height:100%;display:flex;flex-direction:column;border:2px solid}
.choice-btn::before{content:'';position:absolute;top:0;left:-100%;width:100%;height:100%;transition:left 0.7s ease}
.choice-btn::after{content:'';position:absolute;top:0;left:0;width:100%;height:100%;opacity:0;transition:opacity 0.3s}
.choice-btn:hover::before{left:100%}
.choice-btn:hover::after{opacity:1}
.choice-btn:hover{transform:scale(1.04) translateY(-3px)}
.choice-btn:active{transform:scale(0.98) translateY(0)}
.choice-head{display:flex;align-items:center;justify-content:center;gap:8px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px dashed;transition:border-color 0.4s}
.choice-emoji{font-size:24px;animation:float 3s ease-in-out infinite;transition:filter 0.4s}
@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-4px)}}
.choice-num{font-weight:900;font-size:16px;letter-spacing:1px;transition:all 0.4s;color:var(--c-color)}
.choice-text{color:var(--c-color);font-size:var(--c-size);line-height:1.55;overflow:hidden;display:-webkit-box;-webkit-line-clamp:6;-webkit-box-orient:vertical;text-align:justify;text-shadow:0 1px 3px rgba(0,0,0,0.6);transition:color 0.4s ease,text-shadow 0.4s ease}
.mygo-footer{text-align:center;margin-top:14px;padding-top:12px;font-size:12px;opacity:0.8;letter-spacing:2px;position:relative;z-index:1;transition:all 0.4s}

.theme-cyber{--c-color:#e8f4f8;background:linear-gradient(135deg,#0a1628 0%,#0d2847 30%,#1a3a5c 60%,#0a1f3d 100%);box-shadow:0 4px 20px rgba(0,212,255,0.25),0 0 40px rgba(0,180,216,0.1),inset 0 1px 0 rgba(0,212,255,0.1)}
.theme-cyber::before{background:radial-gradient(ellipse at 30% 20%,rgba(0,245,255,0.15) 0%,transparent 50%),radial-gradient(ellipse at 70% 80%,rgba(0,119,182,0.1) 0%,transparent 50%)}
