.theme-cyber .choice-btn::before{background:linear-gradient(90deg,transparent,rgba(0,245,255,0.3),transparent)}
.theme-cyber .choice-btn::after{background:radial-gradient(circle at center,rgba(0,245,255,0.15),transparent)}
