.theme-mystic{--c-color:#e8f4f8;background:linear-gradient(135deg,#1a0a2e 0%,#2d1b4e 30%,#4a1942 60%,#16082a 100%);box-shadow:0 4px 20px rgba(157,78,221,0.25),0 0 40px rgba(255,111,216,0.1),inset 0 1px 0 rgba(255,111,216,0.1)}
