@media (max-width:768px){.mygo-container{padding:16px;border-radius:14px}.mygo-title{font-size:26px}.choice-grid{gap:12px}.choice-btn{padding:14px 12px}.choice-emoji{font-size:22px}.choice-num{font-size:15px}.choice-text{font-size:calc(var(--c-size) - 1px)}.settings-panel{width:220px;right:8px;top:50px}}
@media (max-width:480px){.mygo-container{padding:14px;border-radius:12px}.mygo-title{font-size:24px}.choice-grid{gap:10px}.choice-btn{padding:12px 10px;border-radius:12px}.choice-head{gap:6px;margin-bottom:8px;padding-bottom:6px}.choice-emoji{font-size:20px}.choice-num{font-size:14px}.choice-text{font-size:calc(var(--c-size) - 2px);-webkit-line-clamp:8}.mygo-footer{font-size:11px}.settings-btn{width:32px;height:32px;font-size:18px;top:10px;right:10px}.settings-panel{width:200px;padding:12px}}
</style>
</head>
<body>
<div class="mygo-container theme-cyber">
<button class="settings-btn" onclick="toggleSettings()">⚙️</button>
<div class="settings-panel" id="settingsPanel">
<div class="settings-section">
<label class="settings-label">⚡ Hành động khi nhấp</label>
<div class="mode-options">
<button class="option-btn active" onclick="setMode('fill')">Điền vào khung chat</button>
<button class="option-btn" onclick="setMode('send')">Gửi ngay lập tức</button>
</div>
</div>
<div class="settings-section">
<label class="settings-label">📐 Chế độ bố cục</label>
<div class="layout-options">
<button class="option-btn active" onclick="setLayout('grid')">Lưới 2×2</button>
<button class="option-btn" onclick="setLayout('vertical')">Danh sách dọc</button>
</div>
</div>
<div class="settings-section">
<label class="settings-label">🎨 Phong cách chủ đề</label>
<div class="theme-options">
<button class="theme-btn cyber active" onclick="setTheme('cyber')" title="Cyber Neon"></button>
<button class="theme-btn mystic" onclick="setTheme('mystic')" title="Bụi Sao Mộng Ảo"></button>
<button class="theme-btn forest" onclick="setTheme('forest')" title="Rừng Ngọc Bích"></button>
<button class="theme-btn royal" onclick="setTheme('royal')" title="Hoàng Gia Kim Điển"></button>
<button class="theme-btn mono" onclick="setTheme('mono')" title="Đen Trắng Cực Hạn"></button>
<button class="theme-btn sakura" onclick="setTheme('sakura')" title="Thiếu Nữ Anh Đào"></button>
<button class="theme-btn sunset" onclick="setTheme('sunset')" title="Dư Âm Hoàng Hôn"></button>
<button class="theme-btn crimson" onclick="setTheme('crimson')" title="Ác Mộng Thẫm Đỏ"></button>
</div>
</div>
<div class="settings-section">
<label class="settings-label">🅰️ Kích cỡ chữ</label>
<input type="range" class="range-input" min="12" max="20" step="0.5" value="13.5" oninput="setFontSize(this.value)">
</div>
<div class="settings-section">
<div class="settings-head">
<label class="settings-label" style="margin:0">🖌️ Màu chữ tùy chọn</label>
<button class="reset-text" onclick="resetFontColor()">↺ Mặc định chủ đề</button>
</div>
<input type="color" class="color-input" value="#e8f4f8" onchange="setFontColor(this.value)">
</div>
<div class="settings-section" style="border-top: 1px solid rgba(255,255,255,0.1); padding-top: 14px;">
<button class="option-btn" onclick="resetAllSettings()">↻ Khôi phục cài đặt gốc</button>
</div>
</div>
<div class="mygo-header">
<div class="mygo-title">▸ Chọn con đường của bạn ◂</div>
<div class="mygo-subtitle">— Tìm kiếm câu trả lời trong mê cung —</div>
</div>
<div class="choice-grid" id="choiceGrid">
    <button class="choice-btn" onclick="handleStoryClick(this)">
        <div class="choice-head"><span class="choice-emoji">$1</span><span class="choice-num">Tùy chọn 1</span></div>
        <div class="choice-text">$2</div>
    </button>
    <button class="choice-btn" onclick="handleStoryClick(this)">
        <div class="choice-head"><span class="choice-emoji">$3</span><span class="choice-num">Tùy chọn 2</span></div>
        <div class="choice-text">$4</div>
    </button>
    <button class="choice-btn" onclick="handleStoryClick(this)">
        <div class="choice-head"><span class="choice-emoji">$5</span><span class="choice-num">Tùy chọn 3</span></div>
        <div class="choice-text">$6</div>
    </button>
    <button class="choice-btn" onclick="handleStoryClick(this)">
        <div class="choice-head"><span class="choice-emoji">$7</span><span class="choice-num">Tùy chọn 4</span></div>
        <div class="choice-text">$8</div>
    </button>
</div>
<div class="mygo-footer">✦ Lựa chọn của bạn sẽ quyết định định mệnh ✦</div>
</div>
<script>
const mygoContainer = document.querySelector('.mygo-container');
const choiceGrid = document.getElementById('choiceGrid');
const settingsPanel = document.getElementById('settingsPanel');
const settingsBtn = document.querySelector('.settings-btn');
const fontSizeSlider = document.querySelector('.range-input');
const fontColorPicker = document.querySelector('.color-input');
const themeDefaultColors = {'cyber':'#e8f4f8','mystic':'#e8f4f8','forest':'#e8f4f8','royal':'#e8f4f8','mono':'#dddddd','sakura':'#8b4563','sunset':'#fff5ee','crimson':'#ffe6e6'};

function toggleSettings(){settingsPanel.classList.toggle('active')}
function setLayout(type){const btns=document.querySelectorAll('.layout-options .option-btn');btns.forEach(b=>b.classList.remove('active'));if(type==='vertical'){choiceGrid.classList.add('vertical');btns[1].classList.add('active')}else{choiceGrid.classList.remove('vertical');btns[0].classList.add('active')}localStorage.setItem('layout',type)}
function setMode(mode){const btns=document.querySelectorAll('.mode-options .option-btn');btns.forEach(b=>b.classList.remove('active'));if(mode==='send'){btns[1].classList.add('active')}else{btns[0].classList.add('active')}localStorage.setItem('sendMode',mode)}
function setTheme(theme){mygoContainer.className='mygo-container theme-'+theme;document.querySelectorAll('.theme-btn').forEach(b=>b.classList.remove('active'));document.querySelector('.theme-btn.'+theme).classList.add('active');localStorage.setItem('theme',theme);if(localStorage.getItem('fontColor')===null){resetFontColor()}}
function setFontSize(val){document.documentElement.style.setProperty('--c-size',val+'px');localStorage.setItem('fontSize',val)}
function setFontColor(val){mygoContainer.style.setProperty('--c-color',val);localStorage.setItem('fontColor',val)}
function resetFontColor(){mygoContainer.style.removeProperty('--c-color');localStorage.removeItem('fontColor');const currentTheme=mygoContainer.classList[1].replace('theme-','');fontColorPicker.value=themeDefaultColors[currentTheme]||'#e8f4f8'}
function resetAllSettings(){if(confirm('Bạn có chắc chắn muốn khôi phục tất cả cài đặt gốc không?')){['layout','sendMode','theme','fontSize','fontColor'].forEach(k=>localStorage.removeItem(k));window.location.reload()}}
function handleStoryClick(btnElement) {
    // 1. Lấy nội dung text từ div con .choice-text
    const textDiv = btnElement.querySelector('.choice-text');
    if (!textDiv) return;

    // Lấy text thuần túy, loại bỏ khoảng trắng thừa đầu đuôi
    const text = textDiv.innerText.trim();

    // 2. Tìm khung chat trong parent (Silly Tavern)
    const textarea = parent.document.querySelector('#send_textarea');

    if (textarea) {
        // Set giá trị
        textarea.value = text;

        // Dispatch event input để Vue/React của Silly Tavern cập nhật state
        textarea.dispatchEvent(new Event('input', { bubbles: true }));
        textarea.focus();

        // 3. Kiểm tra chế độ gửi
        if (localStorage.getItem('sendMode') === 'send') {
            const sendBtn = parent.document.querySelector('#send_but');
            if (sendBtn) {
                // Delay cực ngắn để đảm bảo biến textarea đã update
                setTimeout(() => sendBtn.click(), 50); 
            }
        }
    } else {
        console.error("MyGO Error: Không tìm thấy #send_textarea. Hãy kiểm tra lại ID của Silly Tavern.");
        alert("Lỗi: Không tìm thấy khung chat của Silly Tavern!");
    }
}

window.addEventListener('load',()=>{
    const savedTheme = localStorage.getItem('theme') || 'cyber';
    setTheme(savedTheme);
    setLayout(localStorage.getItem('layout')||'grid');
    setMode(localStorage.getItem('sendMode')||'fill');
    const savedFontSize = localStorage.getItem('fontSize');
    if(savedFontSize){setFontSize(savedFontSize);fontSizeSlider.value=savedFontSize}
    const savedFontColor = localStorage.getItem('fontColor');
    if(savedFontColor){setFontColor(savedFontColor);fontColorPicker.value=savedFontColor}
    else{resetFontColor()}
});

document.addEventListener('click',e=>{if(!settingsPanel.contains(e.target)&&!settingsBtn.contains(e.target))settingsPanel.classList.remove('active')});
</script>
</body>
</html>
